class State:
    __slots__ = ['candidate', 'votes', 'last_vote']

    def __init__(self, cand, votes, last):
        self.candidate = cand
        self.votes = votes
        self.last_vote = last

    def beats(self, other, extra):
        if self.votes + extra > other.votes:
            return True
        elif self.votes + extra == other.votes:
            return self.last_vote < other.last_vote
        else:
            return False

def main():
    candidates, seats, people, voted = map(int, input().split())
    votes = [0 for i in range(candidates)]
    last_vote = [0 for i in range(candidates)]

    if candidates == 1:
        print(1)
        return

    v = list(map(int, input().split()))
    for t in range(voted):
        cand = v[t] - 1
        votes[cand] += 1
        last_vote[cand] = t

    states = [State(i, votes[i], last_vote[i]) for i in range(candidates)]
    states_sorted = sorted(states, key=lambda x: (-x.votes, x.last_vote))
    res = [0 for i in range(candidates)]

    for i in range(candidates):
        current = states[i]
        # Check if candidate can be guaranteed a seat (1)
        # Scenario 1: Already in top k and can't be pushed out
        # Scenario 2: Can't be pushed out even if others get all remaining votes
        # Check if candidate is in top k currently
        temp_states = sorted(states, key=lambda x: (-x.votes, x.last_vote))
        current_pos = -1
        for pos in range(candidates):
            if temp_states[pos].candidate == current.candidate:
                current_pos = pos
                break
        if current_pos < seats and current.votes > 0:
            # Check if remaining votes can push this candidate out
            # The worst case is other candidates get all remaining votes
            remaining_votes = people - voted
            # The candidate at position 'seats' is the one to beat
            if seats < candidates:
                threshold_candidate = temp_states[seats]
                if not current.beats(threshold_candidate, remaining_votes):
                    res[current.candidate] = 2
                else:
                    res[current.candidate] = 1
            else:
                res[current.candidate] = 1
        else:
            # Check if candidate can get into top k with remaining votes (2)
            # The best case is this candidate gets all remaining votes
            total_possible = current.votes + (people - voted)
            if total_possible == 0:
                res[current.candidate] = 3
                continue
            # Compare with the current k-th candidate
            if seats > 0:
                kth_candidate = temp_states[seats - 1]
                # To be in top k, current must beat the k-th candidate with all remaining votes
                if current.beats(kth_candidate, people - voted):
                    res[current.candidate] = 2
                else:
                    res[current.candidate] = 3
            else:
                res[current.candidate] = 3

    # Handle the case where k = n
    if seats == candidates:
        for i in range(candidates):
            if states[i].votes > 0:
                res[states[i].candidate] = 1
            else:
                if people - voted > 0:
                    res[states[i].candidate] = 2
                else:
                    res[states[i].candidate] = 3

    # Handle the case where remaining votes can make a candidate with 0 votes win
    for i in range(candidates):
        if res[i] == 3:
            if votes[i] == 0 and people - voted > 0:
                # Check if adding all remaining votes can make this candidate reach top k
                temp_votes = votes.copy()
                temp_votes[i] += people - voted
                temp_last_vote = last_vote.copy()
                temp_last_vote[i] = people - 1  # latest possible vote
                temp_states = [State(j, temp_votes[j], temp_last_vote[j]) for j in range(candidates)]
                temp_states_sorted = sorted(temp_states, key=lambda x: (-x.votes, x.last_vote))
                for pos in range(min(seats, candidates)):
                    if temp_states_sorted[pos].candidate == i:
                        res[i] = 2
                        break

    print(' '.join(map(str, res)))

main()
